class Dashboard extends React.Component {
  componentDidMount() {
    // Concern A: WebSocket
    this.ws = new WebSocket('/feed');
    this.ws.onmessage = this.handleMessage;

    // Concern B: window resize — mixed into the same method
    window.addEventListener('resize', this.handleResize);
  }

  componentWillUnmount() {
    // Concern A cleanup
    this.ws.close();

    // Concern B cleanup — 50 lines away from where it was set up
    window.removeEventListener('resize', this.handleResize);
  }

  // ...handleMessage and handleResize defined elsewhere in the class
}

function Dashboard() {
  // Concern A: WebSocket — fully self-contained
  useEffect(() => {
    const ws = new WebSocket('/feed');
    ws.onmessage = handleMessage;
    return () => ws.close();
  }, []);

  // Concern B: window resize — also self-contained
  useEffect(() => {
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ...rest of the component
}

// HOC — wraps a component to inject props
function withWindowSize(WrappedComponent) {
  return class extends React.Component {
    state = { width: window.innerWidth, height: window.innerHeight };
    componentDidMount() {
      window.addEventListener('resize', this.handleResize);
    }
    componentWillUnmount() {
      window.removeEventListener('resize', this.handleResize);
    }
    handleResize = () => {
      this.setState({ width: window.innerWidth, height: window.innerHeight });
    };
    render() {
      return <WrappedComponent {...this.props} windowSize={this.state} />;
    }
  };
}

// Now your component is buried inside a HOC:
const MyComponentWithSize = withWindowSize(MyComponent);
// React DevTools shows an extra wrapper in the tree

// Custom hook — no wrapper component, just a function
function useWindowSize() {
  const [size, setSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight,
  });
  useEffect(() => {
    const update = () => setSize({ width: window.innerWidth, height: window.innerHeight });
    window.addEventListener('resize', update);
    return () => window.removeEventListener('resize', update);
  }, []);
  return size;
}

// Usage: call it directly inside any component
function MyComponent() {
  const { width, height } = useWindowSize();
  return <p>Window: {width} x {height}</p>;
}

// Class component: this.state always gets the latest value
class ClassTimer extends React.Component {
  state = { count: 0 };
  handleAlert() {
    setTimeout(() => {
      // `this.state.count` reads whatever state is at timeout time
      alert(`Count is: ${this.state.count}`);
    }, 3000);
  }
  // ...render etc.
}

// Function component: count is captured at render time
function FunctionTimer() {
  const [count, setCount] = useState(0);
  const handleAlert = () => {
    setTimeout(() => {
      // `count` is the value from the render when handleAlert was created
      alert(`Count is: ${count}`); // may be stale if count changed in 3s
    }, 3000);
  };
  // ...return JSX
}

class ErrorBoundary extends React.Component {
  state = { hasError: false };

  static getDerivedStateFromError(error) {
    return { hasError: true };
  }

  componentDidCatch(error, info) {
    console.error('Caught by ErrorBoundary:', error, info.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return this.props.fallback ?? <h2>Something went wrong.</h2>;
    }
    return this.props.children;
  }
}

// Usage: wrap any subtree you want to protect
<ErrorBoundary fallback={<p>Loading failed.</p>}>
  <RiskyComponent />
</ErrorBoundary>

// BEFORE: class component
class UserProfile extends React.Component {
  constructor(props) {
    super(props);
    this.state = { user: null, loading: true };
  }

  componentDidMount() {
    fetchUser(this.props.userId)
      .then(user => this.setState({ user, loading: false }))
      .catch(() => this.setState({ loading: false }));
  }

  componentDidUpdate(prevProps) {
    if (prevProps.userId !== this.props.userId) {
      this.setState({ loading: true });
      fetchUser(this.props.userId)
        .then(user => this.setState({ user, loading: false }))
        .catch(() => this.setState({ loading: false }));
    }
  }

  render() {
    if (this.state.loading) return <Spinner />;
    return <p>{this.state.user?.name}</p>;
  }
}

// AFTER: function component + hooks
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    fetchUser(userId)
      .then(u => { setUser(u); setLoading(false); })
      .catch(() => setLoading(false));
  }, [userId]); // runs on mount AND when userId changes

  if (loading) return <Spinner />;
  return <p>{user?.name}</p>;
}

