// Class: PureComponent does a shallow comparison
class ExpensiveList extends React.PureComponent {
  render() {
    return <ul>{this.props.items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
  }
}

// Equivalent: React.memo wraps a function component
const ExpensiveList = React.memo(function ExpensiveList({ items }) {
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
});
// Both skip re-render when the same props object is passed

class Counter extends React.Component {
  // Class field: no constructor needed for state initialisation
  state = { count: 0 };

  // Arrow class field: no .bind(this) needed in constructor
  handleClick = () => {
    this.setState(s => ({ count: s.count + 1 }));
  };

  render() {
    return (
      <button onClick={this.handleClick}>
        Count: {this.state.count}
      </button>
    );
  }
}
